            import sailpoint.object.Certification;
            import sailpoint.object.CertificationEntity;
            import sailpoint.object.CertificationItem;
            import sailpoint.api.SailPointContext;
            import sailpoint.object.CertificationGroup;
            import sailpoint.object.QueryOptions;
            import sailpoint.object.Filter;
            import sailpoint.object.AbstractCertificationItem;
            import java.util.ArrayList;
            import java.util.HashSet;

            Set validGroups = new HashSet();


            QueryOptions qo = new QueryOptions();
            qo.addFilter(Filter.eq("phase", "Active"));

            List activeCerts = context.getObjects(Certification.class, qo);

            for (Certification cert : activeCerts) {

            List entities = cert.getEntities();
            if (entities == null) continue;

            for (CertificationEntity entity : entities) {

            List items = entity.getItems();
            if (items == null) continue;

            for (CertificationItem item : items) {

            if  (item.getSummaryStatus().equals(AbstractCertificationItem.Status.Open)) {
            List cg = cert. getCertificationGroups(); 
            for(CertificationGroup certGroup : cg){
            if (certGroup != null)
            { 

            validGroups.add(certGroup.getName());
            }
            }

            }
            }
            }
            }

            return new ArrayList(validGroups);
